38→export function createSheetViewport(sourceView = 'plan', sourceFloorId = null, options = {}) {
39→  const defaultRole = sourceView === '3d_preview'
40→    ? 'supplemental'
41→    : ((sourceView === 'plan' || sourceView === 'roof_plan' || sourceView === 'roof_drainage' || sourceView === 'truss_plan')
42→      ? 'primary'
43→      : (sourceView === 'truss_detail' ? 'detail' : 'secondary'));
44→
45→  return {
46→    id: generateId('viewport'),
47→    sourceView,
48→    sourceFloorId,
49→    sourceRefId: options.sourceRefId ?? null,
50→    x: options.x ?? 20,
51→    y: options.y ?? 20,
52→    width: options.width ?? 160,
53→    height: options.height ?? 100,
54→    scale: options.scale ?? 100,
55→    title: options.title ?? '',
56→    rotation: options.rotation ?? 0,
57→    role: options.role ?? defaultRole,
58→    captionPosition: options.captionPosition ?? 'below',
59→    referenceNote: options.referenceNote ?? '',
60→    lockAutoLayout: options.lockAutoLayout ?? false,
61→    phaseId: options.phaseId ?? null,
62→    phaseViewMode: options.phaseViewMode ?? 'all',
63→  };
64→}
