 30→function getSheetPreviewCacheKey(source) {
 31→  return [
 32→    source?.project?.id || 'project',
 33→    source?.project?.updatedAt || 'snapshot',
 34→    source?.activeFloorId || 'all',
 35→    SHEET_PREVIEW_OPTIONS.width,
 36→    SHEET_PREVIEW_OPTIONS.height,
 37→    SHEET_PREVIEW_OPTIONS.preset,
 38→  ].join(':');
 39→}
