 41→function renderSheetPreviewImage(source) {
 42→  const cacheKey = getSheetPreviewCacheKey(source);
 43→  if (!sheetPreviewCache.has(cacheKey)) {
 44→    sheetPreviewCache.set(cacheKey, import('@/three/viewer/renderToImage')
 45→      .then(({ renderSceneToImage }) => {
 46→        const imageUrl = renderSceneToImage(source.project, {
 47→          activeFloorId: source.activeFloorId,
 48→          width: SHEET_PREVIEW_OPTIONS.width,
 49→          height: SHEET_PREVIEW_OPTIONS.height,
 50→          preset: SHEET_PREVIEW_OPTIONS.preset,
 51→        });
 52→
 53→        return imageUrl
 54→          ? { status: 'ready', imageUrl }
 55→          : { status: 'empty', imageUrl: null };
 56→      })
 57→      .catch((error) => {
 58→        sheetPreviewCache.delete(cacheKey);
 59→        throw error;
 60→      }));
 61→  }
 62→
 63→  return sheetPreviewCache.get(cacheKey);
 64→}
