 339→function normalizeSweep(delta, sweepFlag) {
 340→  let result = delta;
 341→  if (sweepFlag && result < 0) result += Math.PI * 2;
 342→  if (!sweepFlag && result > 0) result -= Math.PI * 2;
 343→  return result;
