 669→
 670→  context.save();
 671→  if (!matrixIsIdentity(localMatrix)) {
 672→    context.transform(
 673→      localMatrix.a,
 674→      localMatrix.b,
 675→      localMatrix.c,
 676→      localMatrix.d,
 677→      localMatrix.e,
 678→      localMatrix.f
