 700→    context.strokeStyle = `rgb(${Math.round(style.stroke[0] * 255)}, ${Math.round(style.stroke[1] * 255)}, ${Math.round(style.stroke[2] * 255)})`;
 701→    context.lineWidth = style.strokeWidth;
 702→    context.lineCap = style.lineCap || 'butt';
