 1→function pointInRect(point, rect) {
 2→  return (
 3→    point.x >= rect.x
 4→    && point.x <= rect.x + rect.width
 5→    && point.y >= rect.y
 6→    && point.y <= rect.y + rect.height
 7→  );
 8→}
 9→
10→export function getViewportHandleRects(viewport, handleSize) {
11→  const size = handleSize;
12→  const midX = viewport.x + viewport.width / 2;
13→  const midY = viewport.y + viewport.height / 2;
14→  return {
15→    nw: { x: viewport.x - size / 2, y: viewport.y - size / 2, width: size, height: size },
16→    n: { x: midX - size / 2, y: viewport.y - size / 2, width: size, height: size },
17→    ne: { x: viewport.x + viewport.width - size / 2, y: viewport.y - size / 2, width: size, height: size },
18→    e: { x: viewport.x + viewport.width - size / 2, y: midY - size / 2, width: size, height: size },
19→    se: { x: viewport.x + viewport.width - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
20→    s: { x: midX - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
21→    sw: { x: viewport.x - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
22→    w: { x: viewport.x - size / 2, y: midY - size / 2, width: size, height: size },
23→  };
24→}
25→
26→export function hitTestViewportHandle(point, viewports, handleSize) {
27→  for (let index = viewports.length - 1; index >= 0; index -= 1) {
28→    const viewport = viewports[index];
29→    const handles = getViewportHandleRects(viewport, handleSize);
30→    for (const [key, rect] of Object.entries(handles)) {
31→      if (pointInRect(point, rect)) {
32→        return { viewportId: viewport.id, handle: key };
33→      }
34→    }
35→  }
36→  return null;
37→}
38→
39→export function getViewportRotationHandle(viewport, handleSize) {
40→  const cx = viewport.x + viewport.width / 2;
41→  const stemLength = handleSize * 2.5;
42→  const radius = handleSize / 2;
43→  const stemY1 = viewport.y;
44→  const stemY2 = viewport.y - stemLength;
45→  const cy = stemY2 - radius;
46→  return { cx, cy, radius, stemX: cx, stemY1, stemY2 };
47→}
48→
49→export function hitTestViewportRotationHandle(point, viewport, handleSize) {
50→  const { cx, cy, radius } = getViewportRotationHandle(viewport, handleSize);
51→  const dx = point.x - cx;
52→  const dy = point.y - cy;
53→  return dx * dx + dy * dy <= (radius + handleSize * 0.3) * (radius + handleSize * 0.3);
54→}
55→
56→export function hitTestViewport(point, viewports) {
57→  for (let index = viewports.length - 1; index >= 0; index -= 1) {
58→    const viewport = viewports[index];
59→    if (pointInRect(point, viewport)) {
60→      return viewport;
61→    }
62→  }
63→  return null;
64→}
