 18→function screenToModel(screenX, screenY, viewport, svgRect) {
 19→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 20→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 21→  return { x, y };
 22→}
